<?php
require_once 'config.php';
function e($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function n($v){return (int)($v??0);} 
function fdate($v,$time=true){if($v instanceof DateTimeInterface){return $v->format($time?'d/m/Y H:i':'d/m/Y');} if(!$v){return '-';} $t=strtotime((string)$v); return $t?date($time?'d/m/Y H:i':'d/m/Y',$t):(string)$v;}
function exportCsv($conn,$table){$ok=['usuarios','aulas','reservas','progresso']; if(!in_array($table,$ok,true)){http_response_code(400); exit('Tabela invalida');} $rows=getTableData($conn,$table); header('Content-Type:text/csv; charset=UTF-8'); header('Content-Disposition: attachment; filename="'.$table.'.csv"'); $o=fopen('php://output','w'); fwrite($o,"\xEF\xBB\xBF"); if($rows){fputcsv($o,array_keys($rows[0]),';'); foreach($rows as $row){$out=[]; foreach($row as $val){$out[]=$val instanceof DateTimeInterface?$val->format('d/m/Y H:i'):$val;} fputcsv($o,$out,';');}} fclose($o); exit;}
if(isset($_GET['export'])){exportCsv($conn,$_GET['export']);}
$success=''; $error='';
if($_SERVER['REQUEST_METHOD']==='POST' && isset($_POST['action'])){try{switch($_POST['action']){
case 'add_user': executeQuery($conn,'INSERT INTO usuarios (nome_completo,email,username,senha,plano) VALUES (?,?,?,?,?)',[trim($_POST['nome_completo']??''),trim($_POST['email']??''),trim($_POST['username']??''),password_hash($_POST['senha']??'',PASSWORD_DEFAULT),trim($_POST['plano']??'Basico')]); $success='Usuario adicionado com sucesso.'; break;
case 'delete_user': executeQuery($conn,'DELETE FROM usuarios WHERE id_usuario = ?',[n($_POST['id'])]); $success='Usuario removido com sucesso.'; break;
case 'add_aula': executeQuery($conn,'INSERT INTO aulas (nome,tipo,horarios,descricao) VALUES (?,?,?,?)',[trim($_POST['nome']??''),trim($_POST['tipo']??''),trim($_POST['horarios']??''),trim($_POST['descricao']??'')]); $success='Aula adicionada com sucesso.'; break;
case 'delete_aula': executeQuery($conn,'DELETE FROM aulas WHERE id_aula = ?',[n($_POST['id'])]); $success='Aula removida com sucesso.'; break;
case 'add_reserva': executeQuery($conn,'INSERT INTO reservas (id_usuario,id_aula,data_reserva) VALUES (?,?,?)',[n($_POST['id_usuario']),n($_POST['id_aula']),$_POST['data_reserva']??null]); $success='Reserva adicionada com sucesso.'; break;
case 'delete_reserva': executeQuery($conn,'DELETE FROM reservas WHERE id_reserva = ?',[n($_POST['id'])]); $success='Reserva removida com sucesso.'; break;
case 'add_progresso': executeQuery($conn,'INSERT INTO progresso (id_usuario,data,peso,altura,massa_muscular,forca,resistencia,explosividade,velocidade,intensidade) VALUES (?,?,?,?,?,?,?,?,?,?)',[n($_POST['id_usuario']),$_POST['data']??null,$_POST['peso']??0,$_POST['altura']??0,$_POST['massa_muscular']??0,$_POST['forca']??0,$_POST['resistencia']??0,$_POST['explosividade']??0,$_POST['velocidade']??0,$_POST['intensidade']??0]); $success='Progresso adicionado com sucesso.'; break;
case 'delete_progresso': executeQuery($conn,'DELETE FROM progresso WHERE id_progresso = ?',[n($_POST['id'])]); $success='Progresso removido com sucesso.'; break;
}}catch(Throwable $ex){$error='Nao foi possivel concluir a acao: '.$ex->getMessage();}}
$usuarios=getTableData($conn,'usuarios'); $aulas=getTableData($conn,'aulas'); $reservas=getTableData($conn,'reservas'); $progressos=getTableData($conn,'progresso'); $stats=getStats($conn); $plans=['Basico'=>0,'Premium'=>0]; foreach($usuarios as $u){$p=(string)($u['plano']??'Basico'); if(!isset($plans[$p])){$plans[$p]=0;} $plans[$p]++;}
?>
