)}.stat strong{display:block;margin:12px 0 6px;font-size:1.9rem}.btn,.mini-btn{border:0;cursor:pointer;font:inherit;transition:.18s ease}.btn{display:inline-flex;align-items:center;gap:8px;padding:11px 14px;border-radius:14px;background:linear-gradient(135deg,var(--brand),var(--brand2));color:#fff}.btn.alt{background:var(--soft);color:var(--ink)}.btn:hover,.mini-btn:hover{transform:translateY(-1px)}.analytics{display:grid;grid-template-columns:1fr 1fr;gap:18px}.meter{margin-top:14px;display:grid;gap:12px}.meter .bar{padding:12px 14px;border:1px solid var(--line);border-radius:16px;background:#fff}.track{height:10px;border-radius:999px;background:#f2e8dd;overflow:hidden;margin-top:8px}.fill{height:100%;background:linear-gradient(90deg,var(--brand),#d8af70)}.tables{grid-template-columns:repeat(2,minmax(0,1fr))}.table-wrap{padding-top:0}.table-head{padding:22px 22px 12px}.table-tools{display:flex;gap:8px;flex-wrap:wrap}.chip{display:inline-flex;padding:7px 10px;border-radius:999px;background:#f4eadf;font-size:.86rem}table{width:100%;min-width:620px;border-collapse:collapse}th,td{text-align:left;padding:13px 10px;border-bottom:1px solid var(--line);vertical-align:top}th{font-size:.8rem;text-transform:uppercase;color:var(--muted);letter-spacing:.05em;background:#fffaf5;position:sticky;top:0}.scroll{overflow:auto}.mini-btn{display:inline-flex;align-items:center;gap:6px;padding:8px 11px;border-radius:10px;background:var(--bad);color:#fff}.empty{padding:0 22px 22px;color:var(--muted)}.modal{position:fixed;inset:0;display:none;align-items:center;justify-content:center;padding:20px;background:rgba(18,16,15,.55);z-index:20}.modal.open{display:flex}.modal-box{width:min(740px,100%);max-height:90vh;overflow:auto}.modal-top,.modal-body{padding:20px 22px}.close{border:0;background:var(--soft);width:40px;height:40px;border-radius:12px;cursor:pointer}.form{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:14px}.field{display:grid;gap:8px}.field.full,.actions-end{grid-column:1/-1}.field label{font-weight:700}.field input,.field select,.field textarea{width:100%;padding:12px 13px;border:1px solid var(--line);border-radius:14px;background:#fff;font:inherit}.field textarea{min-height:110px;resize:vertical}.actions-end{display:flex;justify-content:flex-end;gap:10px}.page-actions{display:flex;gap:10px;flex-wrap:wrap}.page-actions a{display:inline-flex;align-items:center;gap:8px;padding:11px 14px;border-radius:999px;background:rgba(255,255,255,.08);color:#fff}@media (max-width:1100px){.hero-grid,.boards,.analytics,.tables,.form{grid-template-columns:1fr}}@media (max-width:720px){.wrap{width:min(100% - 16px,100%)}.hero,.toolbar,.boards,.table-wrap,.modal-body,.table-head,.modal-top{padding-left:16px;padding-right:16px}.quick{grid-template-columns:1fr}.page-actions .btn,.toolbar .btn{width:100%;justify-content:center}}</style></head><body>
