<section class="analytics"><article class="card"><div class="toolbar"><div><h3>Distribuicao de planos</h3><p class="muted">Leitura simples da base atual.</p></div></div><div class="table-wrap"><div class="meter"><?php $total=max(1,count($usuarios)); foreach($plans as $label=>$count): $pct=round(($count/$total)*100); ?><div class="bar"><div class="top"><strong><?php echo e($label); ?></strong><span class="chip"><?php echo e($count); ?> usuarios</span></div><div class="track"><div class="fill" style="width:<?php echo e($pct); ?>%"></div></div></div><?php endforeach; ?></div></div></article><article class="card"><div class="toolbar"><div><h3>Ferramentas</h3><p class="muted">Exporte qualquer tabela ou revise os totais rapidamente.</p></div></div><div class="table-wrap"><div class="meter"><div class="bar"><div class="top"><strong>Usuarios</strong><a href="?export=usuarios" class="chip">CSV</a></div></div><div class="bar"><div class="top"><strong>Aulas</strong><a href="?export=aulas" class="chip">CSV</a></div></div><div class="bar"><div class="top"><strong>Reservas</strong><a href="?export=reservas" class="chip">CSV</a></div></div><div class="bar"><div class="top"><strong>Progresso</strong><a href="?export=progresso" class="chip">CSV</a></div></div></div></div></article></section>
