<script>document.addEventListener('DOMContentLoaded',()=>{const modals=document.querySelectorAll('.modal');const closeAll=()=>modals.forEach(m=>m.classList.remove('open'));document.querySelectorAll('[data-modal]').forEach(b=>b.addEventListener('click',()=>{closeAll();document.getElementById(b.dataset.modal).classList.add('open');}));document.querySelectorAll('[data-close]').forEach(b=>b.addEventListener('click',closeAll));modals.forEach(m=>m.addEventListener('click',e=>{if(e.target===m)closeAll();}));document.addEventListener('keydown',e=>{if(e.key==='Escape')closeAll();});});</script>
